func (s *UserService) GetUser(ctx context.Context, id string) (*User, error) {
    user, err := s.repo.FindByID(ctx, id)
    if err != nil {
        return nil, fmt.Errorf("user_get %s: %w", id, err)
    }
    return user, nil
}

// pkg/apperror/errors.go — one package per service
package apperror

import "errors"

var (
    ErrNotFound     = errors.New("resource not found")
    ErrUnauthorized = errors.New("unauthorized")
    ErrConflict     = errors.New("resource conflict")
    ErrValidation   = errors.New("validation failed")
)

// Repository translates DB errors to domain sentinels
func (r *UserRepo) FindByID(ctx context.Context, id string) (*User, error) {
    var u User
    err := r.db.GetContext(ctx, &u, `SELECT * FROM users WHERE id=$1`, id)
    if errors.Is(err, sql.ErrNoRows) {
        return nil, apperror.ErrNotFound  // domain sentinel, not sql
    }
    if err != nil {
        return nil, fmt.Errorf("user_find_by_id: %w", err)
    }
    return &u, nil
}
